def test_encoder_decoder_training():
    """测试编码器-解码器预训练。"""
    print("\n" + "=" * 60)
    print("测试: 编码器-解码器预训练")
    print("=" * 60)

    config = get_default_config()
    config.training.learning_rate = 1e-4
    config.training.batch_size = 8

    tokenizer = GeometryTokenizer(vocab_size=config.encoder.vocab_size)

    encoder = Encoder(
        vocab_size=config.encoder.vocab_size,
        embed_dim=config.encoder.embed_dim,
        num_heads=config.encoder.num_heads,
        num_layers=config.encoder.num_layers,
        ffn_dim=config.encoder.ffn_dim,
        max_seq_len=config.encoder.max_seq_len,
        dropout=0.0,
    )

    decoder = Decoder(
        vocab_size=config.decoder.vocab_size,
        embed_dim=config.decoder.embed_dim,
        num_heads=config.decoder.num_heads,
        num_layers=config.decoder.num_layers,
        ffn_dim=config.decoder.ffn_dim,
        max_seq_len=config.decoder.max_seq_len,
        dropout=0.0,
    )

    trainer = EncoderDecoderTrainer(encoder, decoder, tokenizer, config.training)

    print("\n训练20轮...")
    losses = trainer.train_joint(num_epochs=20, statements_per_epoch=64)

    print(f"\n初始损失: {losses[0]:.4f}")
    print(f"最终损失: {losses[-1]:.4f}")
    print(f"损失下降: {losses[0] - losses[-1]:.4f}")

    loss_decreased = losses[-1] < losses[0]
    print(f"\n损失下降: {loss_decreased}")

    return loss_decreased, losses


